import{_ as a,o,c as t,ag as n}from"./chunks/framework.BYYsWsaA.js";const m=JSON.parse('{"title":"Viewing PDFs","description":"","frontmatter":{},"headers":[],"relativePath":"pdf/viewing-pdfs.md","filePath":"pdf/viewing-pdfs.md"}'),i={name:"pdf/viewing-pdfs.md"};function r(s,e,l,d,h,c){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="viewing-pdfs" tabindex="-1">Viewing PDFs <a class="header-anchor" href="#viewing-pdfs" aria-label="Permalink to &quot;Viewing PDFs&quot;">‚Äã</a></h1><p>Wafflebase stores and displays <strong>PDF files</strong> alongside your sheets, docs, slides, and notes. A PDF is a <em>view-only</em> document type ‚Äî you upload the original file, read it in the browser, and collaborate through comments and presence, but the PDF&#39;s contents are never edited.</p><h2 id="upload-a-pdf" tabindex="-1">Upload a PDF <a class="header-anchor" href="#upload-a-pdf" aria-label="Permalink to &quot;Upload a PDF&quot;">‚Äã</a></h2><ol><li>Open your workspace</li><li>Click the <strong>New</strong> dropdown button</li><li>Select <strong>Upload PDF</strong></li><li>Choose a <code>.pdf</code> file from your computer</li></ol><p>The file uploads and opens in the viewer. It appears in your workspace document list with a PDF badge, and its title defaults to the file name (which you can rename).</p><h2 id="read-a-pdf" tabindex="-1">Read a PDF <a class="header-anchor" href="#read-a-pdf" aria-label="Permalink to &quot;Read a PDF&quot;">‚Äã</a></h2><p>The viewer renders every page in a single continuous scroll and fits each page to the width of your window. Resizing the window ‚Äî or collapsing the sidebar ‚Äî reflows the pages to match. A progress bar shows while the file downloads on first open.</p><ul><li><strong>Scroll</strong> to move through the pages</li><li>Pages render as you reach them, so large files stay responsive</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>PDFs are read-only. To make changes, edit the source elsewhere and upload a new version.</p></div><h2 id="rename-a-pdf" tabindex="-1">Rename a PDF <a class="header-anchor" href="#rename-a-pdf" aria-label="Permalink to &quot;Rename a PDF&quot;">‚Äã</a></h2><p>Click the title in the header to rename the document. The change is reflected in your workspace list right away.</p><h2 id="comment-on-a-pdf" tabindex="-1">Comment on a PDF <a class="header-anchor" href="#comment-on-a-pdf" aria-label="Permalink to &quot;Comment on a PDF&quot;">‚Äã</a></h2><p>Even though the PDF itself can&#39;t be edited, you and your teammates can hold a discussion pinned to specific regions of a page.</p><h3 id="add-a-comment" tabindex="-1">Add a comment <a class="header-anchor" href="#add-a-comment" aria-label="Permalink to &quot;Add a comment&quot;">‚Äã</a></h3><ol><li>Click <strong>Add comment</strong> in the header</li><li>Drag a rectangle over the part of the page you want to comment on</li><li>Type your comment in the composer that appears and post it</li></ol><p>The comment is anchored to that page and region, so it stays put as everyone scrolls.</p><h3 id="the-comments-panel" tabindex="-1">The comments panel <a class="header-anchor" href="#the-comments-panel" aria-label="Permalink to &quot;The comments panel&quot;">‚Äã</a></h3><p>Click <strong>Show comments</strong> in the header to open the side panel. It lists every thread, labeled by page. Select a thread to:</p><ul><li><strong>Reply</strong> to continue the discussion</li><li><strong>Resolve</strong> (or reopen) it once it&#39;s addressed</li><li><strong>Edit</strong> or <strong>Delete</strong> your own comments</li></ul><h2 id="collaborate-in-real-time" tabindex="-1">Collaborate in Real Time <a class="header-anchor" href="#collaborate-in-real-time" aria-label="Permalink to &quot;Collaborate in Real Time&quot;">‚Äã</a></h2><p>PDF documents carry the same live collaboration as the rest of Wafflebase ‚Äî the file bytes stay static, but comments and presence sync instantly:</p><ul><li><strong>Presence</strong> ‚Äî avatars in the header show who else is viewing, and follow each person to the page they&#39;re currently reading</li><li><strong>Comments</strong> ‚Äî new threads and replies appear for everyone without a refresh</li></ul><h3 id="share-a-pdf" tabindex="-1">Share a PDF <a class="header-anchor" href="#share-a-pdf" aria-label="Permalink to &quot;Share a PDF&quot;">‚Äã</a></h3><p>Click <strong>Share</strong> in the header to create a link. Recipients can open and read the PDF ‚Äî and, with an edit link, comment on it ‚Äî without signing in. Viewing is open to anyone with a valid link; commenting requires an edit link or workspace membership. See <a href="/docs/guide/collaboration.html">Collaboration &amp; Sharing</a> for the full sharing flow.</p><h2 id="good-to-know" tabindex="-1">Good to Know <a class="header-anchor" href="#good-to-know" aria-label="Permalink to &quot;Good to Know&quot;">‚Äã</a></h2><ul><li>PDFs are <strong>view-only</strong> ‚Äî there is no in-app annotation or re-export; comments live <em>over</em> the file and never change its bytes</li><li>The original file is stored intact and served only to people with permission to read the document</li><li>Self-hosting? PDF uploads need blob storage configured ‚Äî see <a href="/docs/developers/self-hosting.html">Self-Hosting</a></li></ul>',26)])])}const g=a(i,[["render",r]]);export{m as __pageData,g as default};
